#pragma warning disable CS1591, CS1573
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
namespace 
{
    [ApiController]
    [Route("api/[controller]")]
    public class ProductController : ControllerBase
    {
        private readonly global::IProductService iProductService;
        public ProductController(global::IProductService iProductService)
        {
            this.iProductService = iProductService;
        }

        [Route("GetProductByCode/{code}")]
        [HttpGet]
        public string GetProductByCode([FromRoute] string code, [FromQuery] int page)
        {
            return this.iProductService.GetProductByCode(code, page);                    
        }
    }
}
